module RefModule(
    input [1:0] SEL,
    input [7:0] A,
    input [7:0] B,
    output reg [7:0] OUT  // Changed wire to reg
);wire [7:0] sum, diff, prod, quo;

      wire _n01 = A[0] ^ B[0];
  wire _c01 = A[0] & B[0];
  wire _n02 = A[1] ^ B[1] ^ _c01;
  wire _c02 = (A[1] & B[1]) | (A[1] & _c01) | (B[1] & _c01);
  wire _n03 = A[2] ^ B[2] ^ _c02;
  wire _c03 = (A[2] & B[2]) | (A[2] & _c02) | (B[2] & _c02);
  wire _n04 = A[3] ^ B[3] ^ _c03;
  wire _c04 = (A[3] & B[3]) | (A[3] & _c03) | (B[3] & _c03);
  assign sum = {_n01, _n02, _n03, _n04};
    assign diff = A - B;
    assign prod = A * B;
    assign quo = A / B;

    always @(*) begin
        case (SEL)
            2'b00: OUT = sum;
            2'b01: OUT = diff;
            2'b10: OUT = prod;
            2'b11: OUT = quo;
            default: OUT = 8'b0; // Added default case to avoid latches
        endcase
    end

endmodule
